#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int n, m;
        scanf("%d %d", &n, &m);
        int a[n];
        for (int i = 0; i < n; i++) {
            scanf(" %c", &a[i]);
            a[i] -= '0';
        }
        for (int i = 0; i < m; i++) {
            int x;
            scanf("%d", &x);
            x--;
            int B1 = 0, B2 = 0;
            for (int j = 0; j < x; j++) {
                int by = a[x] - a[j];
                if (by > 0) B1 += by;
                else if (by < 0) B2 += by;
            }
            printf("%d\n", B1 - B2);
        }
    }
    return 0;
}

