code.Java:
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int n = sc.nextInt();
            int m = sc.nextInt();
            int[] a = new int[n];
            String s = sc.next();
            for (int i = 0; i < n; i++) {
                a[i] = s.charAt(i) - '0';
            }
            for (int i = 0; i < m; i++) {
                int x = sc.nextInt() - 1;
                int B1 = 0, B2 = 0;
                for (int j = 0; j < x; j++) {
                    int by = a[x] - a[j];
                    if (by > 0) B1 += by;
                    else if (by < 0) B2 += by;
                }
                System.out.println(B1 - B2);
            }
        }
    }
}

